"use client";

import { useCallback, useMemo, useState } from "react";
import { Stage1 } from "@/components/Stage1";
import { Stage2 } from "@/components/Stage2";
import {
  bufferToISO,
  todayISO,
  weeksBetween,
} from "@/lib/dates";
import type {
  DateField,
  Diagnosis,
  Drug,
  Eye,
  OnlyEye,
  Stage,
  Stage1State,
  Stage2State,
} from "@/lib/types";

const YEAR_HINT = 2026;

const initialStage1: Stage1State = {
  lastInjection: "",
  octM: "",
  noOfWeeks: null,
  nextInjectionWeeks: null,
  adjustment: null,
};

const initialStage2: Stage2State = {
  recentInjection: "",
  eye: null,
  diagnosis: null,
  onlyEye: null,
  drug: null,
  fuOctBefore: false,
};

function recomputeWeeks(
  lastInjection: string,
  octM: string,
  adjustment: Stage1State["adjustment"]
): Pick<Stage1State, "noOfWeeks" | "nextInjectionWeeks"> {
  const weeks =
    lastInjection && octM ? weeksBetween(lastInjection, octM) : null;
  if (weeks === null) {
    return { noOfWeeks: null, nextInjectionWeeks: null };
  }
  let next: number | null = null;
  if (adjustment === "keep") next = weeks;
  else if (adjustment === "extend") next = weeks + 2;
  else if (adjustment === "shorten") next = weeks - 2;
  return { noOfWeeks: weeks, nextInjectionWeeks: next };
}

export default function Home() {
  const [stage, setStage] = useState<Stage>(1);
  const [stage1, setStage1] = useState<Stage1State>(initialStage1);
  const [stage2, setStage2] = useState<Stage2State>(initialStage2);
  const [activeField, setActiveField] = useState<DateField>("lastInjection");
  const [digitBuffer, setDigitBuffer] = useState("");

  const commitBuffer = useCallback(
    (field: DateField, buffer: string) => {
      const iso = bufferToISO(buffer, YEAR_HINT);
      if (!iso) return;

      if (field === "lastInjection" || field === "octM") {
        setStage1((prev) => {
          const next = {
            ...prev,
            [field]: iso,
          };
          const recomputed = recomputeWeeks(
            next.lastInjection,
            next.octM,
            next.adjustment
          );
          return { ...next, ...recomputed };
        });
      } else if (field === "recentInjection") {
        setStage2((prev) => ({ ...prev, recentInjection: iso }));
      }
      setDigitBuffer("");
    },
    []
  );

  const onSelectField = useCallback((field: DateField) => {
    setActiveField(field);
    setDigitBuffer("");
  }, []);

  const onDigit = useCallback(
    (d: string) => {
      setDigitBuffer((prev) => {
        const next = (prev + d).replace(/\D/g, "").slice(0, 8);
        // Auto-commit when complete (4 = DDMM with year hint, or 8 = DDMMYYYY)
        if (next.length === 4 || next.length === 8) {
          // defer commit so state updates cleanly
          queueMicrotask(() => commitBuffer(activeField, next));
        }
        return next;
      });
    },
    [activeField, commitBuffer]
  );

  const onClear = useCallback(() => {
    setDigitBuffer("");
    if (activeField === "lastInjection" || activeField === "octM") {
      setStage1((prev) => {
        const next = { ...prev, [activeField]: "" };
        const recomputed = recomputeWeeks(
          next.lastInjection,
          next.octM,
          next.adjustment
        );
        return {
          ...next,
          ...recomputed,
          adjustment: recomputed.noOfWeeks === null ? null : prev.adjustment,
          nextInjectionWeeks:
            recomputed.noOfWeeks === null ? null : recomputed.nextInjectionWeeks,
        };
      });
    } else {
      setStage2((prev) => ({ ...prev, recentInjection: "" }));
    }
  }, [activeField]);

  const onBackspace = useCallback(() => {
    setDigitBuffer((prev) => prev.slice(0, -1));
  }, []);

  const onToday = useCallback(() => {
    const iso = todayISO();
    setDigitBuffer("");
    if (activeField === "lastInjection" || activeField === "octM") {
      setStage1((prev) => {
        const next = { ...prev, [activeField]: iso };
        const recomputed = recomputeWeeks(
          next.lastInjection,
          next.octM,
          next.adjustment
        );
        return { ...next, ...recomputed };
      });
    } else {
      setStage2((prev) => ({ ...prev, recentInjection: iso }));
    }
  }, [activeField]);

  const applyAdjustment = useCallback(
    (adjustment: "keep" | "extend" | "shorten") => {
      setStage1((prev) => {
        if (prev.noOfWeeks === null) return prev;
        const nextWeeks =
          adjustment === "keep"
            ? prev.noOfWeeks
            : adjustment === "extend"
              ? prev.noOfWeeks + 2
              : prev.noOfWeeks - 2;
        return {
          ...prev,
          adjustment,
          nextInjectionWeeks: nextWeeks,
        };
      });
    },
    []
  );

  const nextWeeks = stage1.nextInjectionWeeks ?? 0;

  const stageLabel = useMemo(
    () => (stage === 1 ? "Interval calculator" : "Barcode generator"),
    [stage]
  );

  return (
    <div className="app-shell">
      <header className="app-header">
        <div>
          <p className="app-kicker">Clinical tool</p>
          <h1 className="app-title">Injection Calculator</h1>
          <p className="app-desc">{stageLabel}</p>
        </div>
        <div className="stage-pills">
          <span className={stage === 1 ? "pill pill-on" : "pill"}>1</span>
          <span className="pill-line" />
          <span className={stage === 2 ? "pill pill-on" : "pill"}>2</span>
        </div>
      </header>

      <main>
        {stage === 1 ? (
          <Stage1
            state={stage1}
            activeField={
              activeField === "recentInjection" ? "lastInjection" : activeField
            }
            digitBuffer={digitBuffer}
            onSelectField={onSelectField}
            onDigit={onDigit}
            onClear={onClear}
            onBackspace={onBackspace}
            onToday={onToday}
            onKeep={() => applyAdjustment("keep")}
            onExtend={() => applyAdjustment("extend")}
            onShorten={() => applyAdjustment("shorten")}
            onContinue={() => {
              setStage(2);
              setActiveField("recentInjection");
              setDigitBuffer("");
            }}
          />
        ) : (
          <Stage2
            nextInjectionWeeks={nextWeeks}
            state={stage2}
            activeField={activeField}
            digitBuffer={digitBuffer}
            onSelectField={onSelectField}
            onDigit={onDigit}
            onClear={onClear}
            onBackspace={onBackspace}
            onToday={onToday}
            onSetEye={(eye: Eye) => setStage2((p) => ({ ...p, eye }))}
            onSetDiagnosis={(diagnosis: Diagnosis) =>
              setStage2((p) => ({ ...p, diagnosis }))
            }
            onSetOnlyEye={(onlyEye: OnlyEye) =>
              setStage2((p) => ({ ...p, onlyEye }))
            }
            onSetDrug={(drug: Drug) => setStage2((p) => ({ ...p, drug }))}
            onToggleFu={() =>
              setStage2((p) => ({ ...p, fuOctBefore: !p.fuOctBefore }))
            }
            onBack={() => {
              setStage(1);
              setActiveField("lastInjection");
              setDigitBuffer("");
            }}
          />
        )}
      </main>

      <footer className="app-footer">
        Dates: type DDMM (year {YEAR_HINT}) or full DDMMYYYY · Q-week adjusts
        by weeks from today to recent injection
      </footer>
    </div>
  );
}

export type Eye = "RE" | "LE";
export type Diagnosis = "wAMD" | "PCV";
export type Drug = "Eylea 8mg" | "Eylea 2mg" | "Vabysmo" | "Lucentis";
export type OnlyEye = "RE only eye" | "LE only eye" | null;
export type DateField = "lastInjection" | "octM" | "recentInjection";
export type Stage = 1 | 2;

export interface Stage1State {
  lastInjection: string; // YYYY-MM-DD or empty
  octM: string;
  noOfWeeks: number | null;
  nextInjectionWeeks: number | null;
  adjustment: "keep" | "extend" | "shorten" | null;
}

export interface Stage2State {
  recentInjection: string;
  eye: Eye | null;
  diagnosis: Diagnosis | null;
  onlyEye: OnlyEye;
  drug: Drug | null;
  fuOctBefore: boolean;
}

export interface AppState {
  stage: Stage;
  stage1: Stage1State;
  stage2: Stage2State;
  activeField: DateField;
  digitBuffer: string;
}

/** Format a Date as YYYY-MM-DD in local time */
export function toISODate(d: Date): string {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, "0");
  const day = String(d.getDate()).padStart(2, "0");
  return `${y}-${m}-${day}`;
}

/** Parse YYYY-MM-DD as local date (not UTC) */
export function parseISODate(iso: string): Date | null {
  if (!iso || !/^\d{4}-\d{2}-\d{2}$/.test(iso)) return null;
  const [y, m, d] = iso.split("-").map(Number);
  const date = new Date(y, m - 1, d);
  if (
    date.getFullYear() !== y ||
    date.getMonth() !== m - 1 ||
    date.getDate() !== d
  ) {
    return null;
  }
  return date;
}

/** Display as DD / MM / YYYY */
export function formatDisplayDate(iso: string): string {
  const d = parseISODate(iso);
  if (!d) return "__ / __ / ____";
  const dd = String(d.getDate()).padStart(2, "0");
  const mm = String(d.getMonth() + 1).padStart(2, "0");
  const yyyy = d.getFullYear();
  return `${dd} / ${mm} / ${yyyy}`;
}

/** Display partial buffer as DD / MM / YYYY while typing (digits = DDMM or DDMMYYYY) */
export function formatBufferDisplay(buffer: string, yearHint = 2026): string {
  const digits = buffer.replace(/\D/g, "").slice(0, 8);
  const dd = digits.slice(0, 2).padEnd(2, "_");
  const mm = digits.slice(2, 4).padEnd(2, "_");
  let yyyy: string;
  if (digits.length <= 4) {
    yyyy = String(yearHint);
  } else {
    yyyy = digits.slice(4, 8).padEnd(4, "_");
  }
  return `${dd} / ${mm} / ${yyyy}`;
}

/**
 * Build ISO date from digit buffer.
 * - 4 digits: DDMM → use yearHint
 * - 8 digits: DDMMYYYY
 */
export function bufferToISO(buffer: string, yearHint = 2026): string | null {
  const digits = buffer.replace(/\D/g, "");
  if (digits.length !== 4 && digits.length !== 8) return null;

  const dd = parseInt(digits.slice(0, 2), 10);
  const mm = parseInt(digits.slice(2, 4), 10);
  const yyyy =
    digits.length === 8 ? parseInt(digits.slice(4, 8), 10) : yearHint;

  if (mm < 1 || mm > 12 || dd < 1 || dd > 31) return null;
  const date = new Date(yyyy, mm - 1, dd);
  if (
    date.getFullYear() !== yyyy ||
    date.getMonth() !== mm - 1 ||
    date.getDate() !== dd
  ) {
    return null;
  }
  return toISODate(date);
}

/** Whole weeks between two dates (signed: positive if end > start) */
export function weeksBetween(startISO: string, endISO: string): number | null {
  const start = parseISODate(startISO);
  const end = parseISODate(endISO);
  if (!start || !end) return null;
  const ms = end.getTime() - start.getTime();
  return Math.round(ms / (7 * 24 * 60 * 60 * 1000));
}

/** Signed week difference: recent relative to today (positive if recent is later) */
export function weeksFromToday(iso: string, today = new Date()): number | null {
  const d = parseISODate(iso);
  if (!d) return null;
  const t = new Date(today.getFullYear(), today.getMonth(), today.getDate());
  const ms = d.getTime() - t.getTime();
  return Math.round(ms / (7 * 24 * 60 * 60 * 1000));
}

export function todayISO(): string {
  return toISODate(new Date());
}

import type { Stage2State } from "./types";
import { weeksFromToday } from "./dates";

/**
 * Build the 2D barcode text per clinical spec.
 *
 * Template:
 * <<< List: {eye} {drug}; {eye} {dx}; Q{n}wk  MP {eye}
 * Amsler grid, AREDS2 info
 * [Protect RE/LE if only-eye]
 * FU Same Day VR Clinic VA IOP MPBE   OR   FU VR Clinic 1/52 before injection VA IOP MPBE
 * <<< OCT-m BE n/v MPBE
 */
export function buildBarcodeText(
  nextInjectionWeeks: number,
  stage2: Stage2State
): { text: string; qWeeks: number } | null {
  const { eye, diagnosis, drug, recentInjection, onlyEye, fuOctBefore } =
    stage2;

  if (!eye || !diagnosis || !drug || !recentInjection) return null;

  const delta = weeksFromToday(recentInjection);
  if (delta === null) return null;

  // Today → same; earlier → minus; later → plus
  const qWeeks = nextInjectionWeeks + delta;

  const lines: string[] = [
    `<<< List: ${eye} ${drug}; ${eye} ${diagnosis}; Q${qWeeks}wk  MP ${eye}`,
    "Amsler grid, AREDS2 info",
  ];

  if (onlyEye === "RE only eye") {
    lines.push("Protect RE");
  } else if (onlyEye === "LE only eye") {
    lines.push("Protect LE");
  }

  if (fuOctBefore) {
    lines.push("FU VR Clinic 1/52 before injection VA IOP MPBE");
  } else {
    lines.push("FU Same Day VR Clinic VA IOP MPBE");
  }

  lines.push("<<< OCT-m BE n/v MPBE");

  return { text: lines.join("\n"), qWeeks };
}

"use client";

import { formatBufferDisplay, formatDisplayDate } from "@/lib/dates";

interface DateFieldProps {
  label: string;
  value: string;
  active: boolean;
  digitBuffer: string;
  onSelect: () => void;
}

export function DateFieldDisplay({
  label,
  value,
  active,
  digitBuffer,
  onSelect,
}: DateFieldProps) {
  const display =
    active && digitBuffer.length > 0
      ? formatBufferDisplay(digitBuffer)
      : value
        ? formatDisplayDate(value)
        : formatBufferDisplay("");

  return (
    <button
      type="button"
      onClick={onSelect}
      className={["date-field", active ? "date-field-active" : ""]
        .filter(Boolean)
        .join(" ")}
    >
      <span className="date-field-label">{label}</span>
      <span className="date-field-value font-mono tracking-wide">{display}</span>
    </button>
  );
}

"use client";

interface NumberPadProps {
  onDigit: (d: string) => void;
  onClear: () => void;
  onBackspace: () => void;
  onToday: () => void;
}

export function NumberPad({
  onDigit,
  onClear,
  onBackspace,
  onToday,
}: NumberPadProps) {
  const keys = ["1", "2", "3", "4", "5", "6", "7", "8", "9"];

  return (
    <div className="grid grid-cols-3 gap-2">
      {keys.map((k) => (
        <button
          key={k}
          type="button"
          onClick={() => onDigit(k)}
          className="num-key"
        >
          {k}
        </button>
      ))}
      <button type="button" onClick={onClear} className="num-key num-key-muted">
        C
      </button>
      <button type="button" onClick={() => onDigit("0")} className="num-key">
        0
      </button>
      <button
        type="button"
        onClick={onBackspace}
        className="num-key num-key-muted"
        aria-label="Backspace"
      >
        ⌫
      </button>
      <button
        type="button"
        onClick={onToday}
        className="col-span-3 num-key num-key-today"
      >
        Today
      </button>
    </div>
  );
}

"use client";

import { DateFieldDisplay } from "./DateField";
import { NumberPad } from "./NumberPad";
import type { DateField, Stage1State } from "@/lib/types";

interface Stage1Props {
  state: Stage1State;
  activeField: DateField;
  digitBuffer: string;
  onSelectField: (field: DateField) => void;
  onDigit: (d: string) => void;
  onClear: () => void;
  onBackspace: () => void;
  onToday: () => void;
  onKeep: () => void;
  onExtend: () => void;
  onShorten: () => void;
  onContinue: () => void;
}

export function Stage1({
  state,
  activeField,
  digitBuffer,
  onSelectField,
  onDigit,
  onClear,
  onBackspace,
  onToday,
  onKeep,
  onExtend,
  onShorten,
  onContinue,
}: Stage1Props) {
  const canAdjust =
    state.noOfWeeks !== null && Number.isFinite(state.noOfWeeks);
  const canContinue =
    state.nextInjectionWeeks !== null && state.adjustment !== null;

  return (
    <div className="stage-grid">
      <div className="panel space-y-4">
        <header className="panel-header">
          <span className="badge">Stage 1</span>
          <h2 className="panel-title">Injection interval</h2>
          <p className="panel-sub">
            Enter dates, then Keep / Extend / Shorten to set next injection
            weeks.
          </p>
        </header>

        <DateFieldDisplay
          label="Date of last injection"
          value={state.lastInjection}
          active={activeField === "lastInjection"}
          digitBuffer={digitBuffer}
          onSelect={() => onSelectField("lastInjection")}
        />
        <DateFieldDisplay
          label="Date of OCT-m"
          value={state.octM}
          active={activeField === "octM"}
          digitBuffer={digitBuffer}
          onSelect={() => onSelectField("octM")}
        />

        <div className="stat-row">
          <div className="stat-card">
            <span className="stat-label">No. of weeks</span>
            <span className="stat-value">
              {state.noOfWeeks !== null ? state.noOfWeeks : "—"}
              <span className="stat-unit"> wk</span>
            </span>
            <span className="stat-hint">OCT-m − last injection</span>
          </div>
          <div className="stat-card stat-card-accent">
            <span className="stat-label">Next injection</span>
            <span className="stat-value">
              {state.nextInjectionWeeks !== null
                ? state.nextInjectionWeeks
                : "—"}
              <span className="stat-unit"> wk</span>
            </span>
            <span className="stat-hint">
              {state.adjustment === "keep" && "Keep interval"}
              {state.adjustment === "extend" && "Extended +2"}
              {state.adjustment === "shorten" && "Shortened −2"}
              {!state.adjustment && "Choose Keep / Extend / Shorten"}
            </span>
          </div>
        </div>

        <div className="action-row">
          <button
            type="button"
            className={[
              "action-btn action-keep",
              state.adjustment === "keep" ? "action-btn-active" : "",
            ]
              .filter(Boolean)
              .join(" ")}
            disabled={!canAdjust}
            onClick={onKeep}
          >
            Keep
          </button>
          <button
            type="button"
            className={[
              "action-btn action-extend",
              state.adjustment === "extend" ? "action-btn-active" : "",
            ]
              .filter(Boolean)
              .join(" ")}
            disabled={!canAdjust}
            onClick={onExtend}
          >
            Extend +2
          </button>
          <button
            type="button"
            className={[
              "action-btn action-shorten",
              state.adjustment === "shorten" ? "action-btn-active" : "",
            ]
              .filter(Boolean)
              .join(" ")}
            disabled={!canAdjust}
            onClick={onShorten}
          >
            Shorten −2
          </button>
        </div>

        <button
          type="button"
          className="primary-btn w-full"
          disabled={!canContinue}
          onClick={onContinue}
        >
          Continue to Stage 2 →
        </button>
      </div>

      <div className="panel">
        <header className="panel-header mb-4">
          <h2 className="panel-title text-lg">Number pad</h2>
          <p className="panel-sub">
            Select a date field, then type DD MM (year defaults to 2026) or
            DDMMYYYY.
          </p>
        </header>
        <NumberPad
          onDigit={onDigit}
          onClear={onClear}
          onBackspace={onBackspace}
          onToday={onToday}
        />
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import QRCode from "qrcode";
import { DateFieldDisplay } from "./DateField";
import { NumberPad } from "./NumberPad";
import { ToggleChip } from "./ToggleChip";
import { buildBarcodeText } from "@/lib/barcode";
import type {
  DateField,
  Diagnosis,
  Drug,
  Eye,
  OnlyEye,
  Stage2State,
} from "@/lib/types";

interface Stage2Props {
  nextInjectionWeeks: number;
  state: Stage2State;
  activeField: DateField;
  digitBuffer: string;
  onSelectField: (field: DateField) => void;
  onDigit: (d: string) => void;
  onClear: () => void;
  onBackspace: () => void;
  onToday: () => void;
  onSetEye: (eye: Eye) => void;
  onSetDiagnosis: (dx: Diagnosis) => void;
  onSetOnlyEye: (v: OnlyEye) => void;
  onSetDrug: (drug: Drug) => void;
  onToggleFu: () => void;
  onBack: () => void;
}

export function Stage2({
  nextInjectionWeeks,
  state,
  activeField,
  digitBuffer,
  onSelectField,
  onDigit,
  onClear,
  onBackspace,
  onToday,
  onSetEye,
  onSetDiagnosis,
  onSetOnlyEye,
  onSetDrug,
  onToggleFu,
  onBack,
}: Stage2Props) {
  const [barcodeText, setBarcodeText] = useState<string | null>(null);
  const [qWeeks, setQWeeks] = useState<number | null>(null);
  const [qrDataUrl, setQrDataUrl] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const canEnter =
    !!state.eye &&
    !!state.diagnosis &&
    !!state.drug &&
    !!state.recentInjection;

  async function handleEnter() {
    setError(null);
    const result = buildBarcodeText(nextInjectionWeeks, state);
    if (!result) {
      setError(
        "Complete required fields: Recent injection date, RE/LE, wAMD/PCV, and drug."
      );
      setBarcodeText(null);
      setQrDataUrl(null);
      return;
    }
    setBarcodeText(result.text);
    setQWeeks(result.qWeeks);
    try {
      const url = await QRCode.toDataURL(result.text, {
        errorCorrectionLevel: "M",
        margin: 2,
        width: 280,
        color: { dark: "#0f172a", light: "#ffffff" },
      });
      setQrDataUrl(url);
    } catch {
      setError("Failed to generate QR code.");
    }
  }

  // Clear barcode when inputs change after generation
  useEffect(() => {
    setBarcodeText(null);
    setQrDataUrl(null);
    setQWeeks(null);
  }, [
    state.eye,
    state.diagnosis,
    state.drug,
    state.recentInjection,
    state.onlyEye,
    state.fuOctBefore,
    nextInjectionWeeks,
  ]);

  return (
    <div className="stage-grid stage-grid-wide">
      <div className="panel space-y-4">
        <header className="panel-header">
          <div className="flex items-center justify-between gap-3">
            <span className="badge">Stage 2</span>
            <button type="button" className="link-btn" onClick={onBack}>
              ← Back to Stage 1
            </button>
          </div>
          <h2 className="panel-title">Clinical options & barcode</h2>
          <p className="panel-sub">
            Next injection interval:{" "}
            <strong className="text-slate-800">{nextInjectionWeeks} weeks</strong>
          </p>
        </header>

        <DateFieldDisplay
          label="Recent past / upcoming injection"
          value={state.recentInjection}
          active={activeField === "recentInjection"}
          digitBuffer={digitBuffer}
          onSelect={() => onSelectField("recentInjection")}
        />

        <section>
          <h3 className="section-label">
            Eye <span className="req">required · pick one</span>
          </h3>
          <div className="chip-row">
            <ToggleChip
              label="RE"
              selected={state.eye === "RE"}
              onClick={() => onSetEye("RE")}
            />
            <ToggleChip
              label="LE"
              selected={state.eye === "LE"}
              onClick={() => onSetEye("LE")}
            />
          </div>
        </section>

        <section>
          <h3 className="section-label">
            Diagnosis <span className="req">required · pick one</span>
          </h3>
          <div className="chip-row">
            <ToggleChip
              label="wAMD"
              selected={state.diagnosis === "wAMD"}
              onClick={() => onSetDiagnosis("wAMD")}
            />
            <ToggleChip
              label="PCV"
              selected={state.diagnosis === "PCV"}
              onClick={() => onSetDiagnosis("PCV")}
            />
          </div>
        </section>

        <section>
          <h3 className="section-label">
            Only eye <span className="opt">optional · pick one or none</span>
          </h3>
          <div className="chip-row">
            <ToggleChip
              label="RE only eye"
              selected={state.onlyEye === "RE only eye"}
              onClick={() =>
                onSetOnlyEye(
                  state.onlyEye === "RE only eye" ? null : "RE only eye"
                )
              }
              variant="optional"
            />
            <ToggleChip
              label="LE only eye"
              selected={state.onlyEye === "LE only eye"}
              onClick={() =>
                onSetOnlyEye(
                  state.onlyEye === "LE only eye" ? null : "LE only eye"
                )
              }
              variant="optional"
            />
          </div>
        </section>

        <section>
          <h3 className="section-label">
            Drug <span className="req">required · pick one</span>
          </h3>
          <div className="chip-row">
            {(
              [
                "Eylea 8mg",
                "Eylea 2mg",
                "Vabysmo",
                "Lucentis",
              ] as Drug[]
            ).map((d) => (
              <ToggleChip
                key={d}
                label={d}
                selected={state.drug === d}
                onClick={() => onSetDrug(d)}
              />
            ))}
          </div>
        </section>

        <section>
          <h3 className="section-label">
            Follow-up <span className="opt">optional</span>
          </h3>
          <div className="chip-row">
            <ToggleChip
              label="FU + OCT-m 1 week before"
              selected={state.fuOctBefore}
              onClick={onToggleFu}
              variant="optional"
            />
          </div>
        </section>

        <button
          type="button"
          className="primary-btn w-full"
          disabled={!canEnter}
          onClick={handleEnter}
        >
          Enter — generate 2D barcode
        </button>
        {error && <p className="error-text">{error}</p>}
      </div>

      <div className="space-y-4">
        <div className="panel">
          <header className="panel-header mb-4">
            <h2 className="panel-title text-lg">Number pad</h2>
            <p className="panel-sub">
              Enter recent past / upcoming injection date.
            </p>
          </header>
          <NumberPad
            onDigit={onDigit}
            onClear={onClear}
            onBackspace={onBackspace}
            onToday={onToday}
          />
        </div>

        <div className="panel barcode-panel">
          <header className="panel-header mb-3">
            <h2 className="panel-title text-lg">2D barcode</h2>
            {qWeeks !== null && (
              <p className="panel-sub">
                Calculated interval: <strong>Q{qWeeks}wk</strong>
              </p>
            )}
          </header>

          {!qrDataUrl && (
            <p className="text-sm text-slate-500">
              Complete required fields and press Enter to generate.
            </p>
          )}

          {qrDataUrl && barcodeText && (
            <div className="barcode-result">
              {/* eslint-disable-next-line @next/next/no-img-element */}
              <img
                src={qrDataUrl}
                alt="2D barcode QR code"
                className="qr-image"
              />
              <pre className="barcode-text">{barcodeText}</pre>
              <button
                type="button"
                className="secondary-btn"
                onClick={() => {
                  navigator.clipboard?.writeText(barcodeText);
                }}
              >
                Copy text
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

"use client";

interface ToggleChipProps {
  label: string;
  selected: boolean;
  onClick: () => void;
  disabled?: boolean;
  variant?: "default" | "optional";
}

export function ToggleChip({
  label,
  selected,
  onClick,
  disabled = false,
  variant = "default",
}: ToggleChipProps) {
  return (
    <button
      type="button"
      onClick={onClick}
      disabled={disabled}
      className={[
        "chip",
        selected ? "chip-selected" : "",
        variant === "optional" ? "chip-optional" : "",
        disabled ? "opacity-40 cursor-not-allowed" : "",
      ]
        .filter(Boolean)
        .join(" ")}
    >
      {label}
    </button>
  );
}
